// Recebe texto do PDF ou mensagem de texto
const text = $input.first().json.text || $input.first().json.body || $input.first().json.message?.conversation || '';

function extract(patterns, text) {
  for (const p of patterns) {
    const m = text.match(p);
    if (m && m[1]) return m[1].trim();
  }
  return null;
}

const result = {
  nome_cliente: extract([/(?:cliente|comprador|destinat[aá]rio|nome)[:\s]*([^\n]{3,60})/i], text),
  numero_venda: extract([/(?:venda|pedido|n[uú]mero|nº|#)[:\s]*([A-Z0-9\-]{5,})/i, /\b([0-9]{8,20})\b/], text),
  etiqueta_ml: extract([/(?:etiqueta|label)[:\s]*([A-Z0-9\-]+)/i, /\b((?:ML|BR)[0-9A-Z]{8,})\b/i], text),
  codigo_produto: extract([/(?:c[oó]d|sku|ref)[:\s]*([A-Z0-9\-_]{3,})/i], text),
  nome_produto: extract([/(?:produto|item|descri[cç][aã]o)[:\s]*([^\n]{3,60})/i], text),
  marca: extract([/(?:marca|brand)[:\s]*([^\n]{2,30})/i], text),
  quantidade: parseInt(extract([/(?:quantidade|qtd)[:\s]*(\d+)/i], text)) || 1,
  status: 'recebido'
};

return [{ json: result }];
